const test_suite = [
  { id: 'T001', prompt_name: 'JTBD Extractor', system_prompt: 'You are a JTBD analyst. Extract the core job from this quote. Return JSON: {"job": "string"}', user_prompt: 'When I get to Monday morning, I just need to know what my team is working on without sending messages.', assertions: [{ field: 'job', contains: 'know', required: true }, { field: 'job', min_length: 30, required: true }] },
  { id: 'T002', prompt_name: 'Bug Severity Classifier', system_prompt: 'Classify bug severity. P0=production down, P1=major broken, P2=minor. Return JSON: {"severity": "P0|P1|P2"}', user_prompt: 'Dashboard 504 timeout affecting 12 enterprise customers since v2.4.1 deployment.', assertions: [{ field: 'severity', equals: 'P0', required: true }] },
  { id: 'T003', prompt_name: 'Sentiment Classifier', system_prompt: 'Classify NPS comment sentiment. Return JSON: {"sentiment": "positive|negative|neutral"}', user_prompt: 'This is the worst project management tool I have used. Everything breaks constantly.', assertions: [{ field: 'sentiment', equals: 'negative', required: true }] }
];
return [{ json: { test_suite, model: process.env.AI_MODEL || 'gpt-4o-mini', run_id: `run-${Date.now()}` } }];

// Run each test case sequentially
const { test_suite, model, run_id } = $input.first().json;
// For n8n sample mode: simulate LLM responses (replace with real HTTP Request loop in production)
const simulated_responses = {
  T001: { job: 'When starting the week, I want to see what my team is working on without sending individual status request messages, so I can plan my time and maintain momentum without interrupting colleagues.' },
  T002: { severity: 'P0' },
  T003: { sentiment: 'negative' }
};
const results = test_suite.map(tc => {
  const response = simulated_responses[tc.id];
  const assertion_results = tc.assertions.map(a => {
    const value = response?.[a.field];
    const checks = [];
    if (a.equals !== undefined) checks.push({ check: `equals '${a.equals}'`, passed: value === a.equals });
    if (a.contains !== undefined) checks.push({ check: `contains '${a.contains}'`, passed: typeof value === 'string' && value.includes(a.contains) });
    if (a.min_length !== undefined) checks.push({ check: `min_length ${a.min_length}`, passed: typeof value === 'string' && value.length >= a.min_length });
    const all_passed = checks.every(c => c.passed);
    return { field: a.field, checks, passed: all_passed, required: a.required };
  });
  const passed = assertion_results.every(a => a.passed);
  return { id: tc.id, prompt_name: tc.prompt_name, passed, response, assertion_results };
});
const total = results.length;
const passed_count = results.filter(r => r.passed).length;
const failed_count = total - passed_count;
return [{ json: { results, run_id, model, meta: { total, passed: passed_count, failed: failed_count, run_at: new Date().toISOString() } } }];

const { results, run_id, model, meta: m } = $input.first().json;
const lines = results.map(r => [
  `  [${r.passed?'PASS':'FAIL'}] ${r.id}: ${r.prompt_name}`,
  ...r.assertion_results.map(a => `    ${a.passed?'✓':'✗'} ${a.field}: ${a.checks.map(c=>c.check+' → '+(c.passed?'pass':'FAIL')).join(', ')}`),
  ''
].join('\n')).join('\n');
const report = [
  `LLM PROMPT REGRESSION REPORT`,
  `Run ID: ${run_id} | Model: ${model} | ${m.run_at}`,
  `Results: ${m.passed}/${m.total} passed${m.failed > 0 ? ' | ⚠️ '+m.failed+' FAILED' : ' | ✅ All passed'}`,
  ``,
  lines,
].join('\n');
return [{ json: { ...($input.first().json), report_text: report } }];
